import{_ as a,c as t,o,ah as i}from"./chunks/framework.C3tt5hnL.js";const m=JSON.parse('{"title":"What is Reactive Route?","description":"","frontmatter":{},"headers":[],"relativePath":"guide/index.md","filePath":"guide/index.md"}'),r={name:"guide/index.md"};function n(s,e,l,c,p,d){return o(),t("div",null,[...e[0]||(e[0]=[i('<h1 id="what-is-reactive-route" tabindex="-1">What is Reactive Route? <a class="header-anchor" href="#what-is-reactive-route" aria-label="Permalink to “What is Reactive Route?”">​</a></h1><p><img src="https://github.com/dkazakov8/reactive-route/blob/master/assets/coverage.svg" alt="coverage"><a href="https://www.npmjs.com/package/reactive-route" target="_blank" rel="noreferrer"><img src="https://img.shields.io/npm/v/reactive-route" alt="npm"></a><img src="https://github.com/dkazakov8/reactive-route/blob/master/assets/core.svg" alt="size-core"><img src="https://github.com/dkazakov8/reactive-route/blob/master/assets/react.svg" alt="size-react"><img src="https://github.com/dkazakov8/reactive-route/blob/master/assets/preact.svg" alt="size-preact"><img src="https://github.com/dkazakov8/reactive-route/blob/master/assets/solid.svg" alt="size-solid"></p><p>Reactive Route is a lightweight, flexible, and reactive router for JavaScript applications.</p><h3 id="framework-and-state-management-agnostic" tabindex="-1">Framework and State Management Agnostic <a class="header-anchor" href="#framework-and-state-management-agnostic" aria-label="Permalink to “Framework and State Management Agnostic”">​</a></h3><p>The core routing logic is framework-agnostic, allowing it to be used with different UI frameworks and state management solutions. Currently, Reactive Route provides official implementations for:</p><ul><li>React + MobX</li><li>React + Observable</li><li>Preact (no compat) + MobX</li><li>Preact (no compat) + Observable</li><li>Solid.js + Solid.js reactivity</li><li>Solid.js + MobX</li><li>Solid.js + Observable</li><li>Vue + Vue reactivity (package in development)</li></ul><h3 id="key-advantages" tabindex="-1">Key Advantages <a class="header-anchor" href="#key-advantages" aria-label="Permalink to “Key Advantages”">​</a></h3><p>Reactive Route offers several advantages that make it a powerful choice for routing in modern web applications:</p><ul><li><p><strong>Lifecycle Hooks</strong>: Built-in <code>beforeEnter</code> and <code>beforeLeave</code> hooks allow you to control navigation flow, perform authentication checks, load data, and handle unsaved changes.</p></li><li><p><strong>Dynamic Component Loading</strong>: Supports dynamically loaded components through async imports (e.g., <code>() =&gt; import(&#39;./pages/Home&#39;)</code>), enabling code splitting and improving application performance.</p></li><li><p><strong>Modular Data Integration</strong>: Supports dynamically loaded modular stores and other data for pages, making state management more organized and efficient.</p></li><li><p><strong>Server-Side Rendering</strong>: Full SSR support for all the supported frameworks, ensuring optimal performance and SEO benefits.</p></li><li><p><strong>Parameter Validation</strong>: Ensures that every dynamic parameter from the URL has a validator, preventing invalid routes and improving application robustness.</p></li><li><p><strong>TypeScript Integration</strong>: Comprehensive TypeScript support for routes, dynamic parameters, and search queries, providing excellent developer experience and type safety.</p></li><li><p><strong>Separation of Concerns</strong>: Functions as a centralized separate layer, eliminating the need for markup like <code>&lt;Route path=&quot;...&quot; /&gt;</code> inside components and keeping your component tree clean.</p></li></ul><p>In the following sections, we&#39;ll explore how to install and use Reactive Route in your applications.</p>',10)])])}const u=a(r,[["render",n]]);export{m as __pageData,u as default};
